SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND (t.MA10/ NULLIF(t.MA200, 0)<1.05) AND (t.MA10_T1/ NULLIF(t.MA200_T1, 0)>1.05) AND (t.Close < 1.12*t.VAP3M) AND (t.Close/ NULLIF(t.Close_T1W, 0) < 1.03) AND (t.D_RSI/ NULLIF(t.D_RSI_T1W, 0) < 0.9) AND (t.D_RSI < 0.62) AND (t.D_MACDdiff< -1.0) AND (t.NP_P0/ NULLIF(t.NP_P1, 0) < 1.08) AND (t.Volume>0.99*t.Volume_3M_P50) ORDER BY t.ticker, t.time